-- Step 1: Add missing columns to product_categories
ALTER TABLE public.product_categories
  ADD COLUMN IF NOT EXISTS description_ar TEXT,
  ADD COLUMN IF NOT EXISTS description_en TEXT,
  ADD COLUMN IF NOT EXISTS slug TEXT,
  ADD COLUMN IF NOT EXISTS icon_url TEXT,
  ADD COLUMN IF NOT EXISTS image_url TEXT,
  ADD COLUMN IF NOT EXISTS parent_category_id UUID,
  ADD COLUMN IF NOT EXISTS display_order INTEGER DEFAULT 0;

-- Step 2: Insert all valid categories from Supabase backup
ON CONFLICT (id) DO NOTHING;

-- Re-grant permissions
GRANT SELECT, INSERT, UPDATE, DELETE ON public.product_categories TO ba9alino_anon;
GRANT SELECT, INSERT, UPDATE, DELETE ON public.product_categories TO ba9alino_admin;

SELECT COUNT(*) AS total_categories FROM public.product_categories;
